"use client";

import { useState } from "react";
import SectionContainer from "@/components/home/SectionContainer";
import { ChevronDownIcon } from "@/components/veiligheid/VeiligheidIcons";

const questions = [
  {
    question: "Blijven gegevens binnen Europa?",
    answer:
      "Verwerking en opslag vinden plaats binnen Europese Azure-regio's.",
  },
  {
    question: "Worden onze gegevens gebruikt om AI-modellen te trainen?",
    answer:
      "Nee. Gegevens binnen CoachScribe worden niet gebruikt om publieke AI-modellen te trainen.",
  },
  {
    question: "Wie is verantwoordelijk onder de AVG?",
    answer:
      "De gebruiker is verwerkingsverantwoordelijke. CoachScribe treedt op als verwerker.",
  },
  {
    question: "Wat betekent aanvullende versleuteling bij opslag?",
    answer:
      "Naast standaardversleuteling binnen Azure gebruiken wij een extra versleutelingslaag. De encryptiesleutels worden beheerd buiten de Azure-omgeving waarin gegevens worden opgeslagen.",
  },
  {
    question: "Is er een verwerkersovereenkomst beschikbaar?",
    answer:
      "Ja. Een verwerkersovereenkomst is beschikbaar op aanvraag.",
  },
  {
    question: "Kunnen sessies en gegevens worden verwijderd?",
    answer:
      "Ja. Gebruikers kunnen sessies en gegevens verwijderen.",
  },
];

export default function VeiligheidFaqSection() {
  const [expandedQuestion, setExpandedQuestion] = useState<string | null>(null);

  return (
    <SectionContainer className="bg-[#F8F9F9]" contentClassName="py-16 md:py-20">
      <div id="faq" className="mx-auto flex w-full max-w-4xl flex-col gap-8">
        <h2 className="font-[var(--font-catamaran)] text-[40px] font-medium leading-[120%] text-[#1D0A00] md:text-[52px]">
          Veelgestelde vragen
        </h2>
        <div className="w-full rounded-2xl border border-black/15 bg-white">
          {questions.map((questionItem, index) => {
            const isExpanded = expandedQuestion === questionItem.question;
            return (
              <div
                key={questionItem.question}
                className={index === 0 ? "" : "border-t border-black/15"}
              >
                <button
                  type="button"
                  aria-expanded={isExpanded}
                  aria-controls={`faq-answer-${index}`}
                  onClick={() =>
                    setExpandedQuestion((previousQuestion) =>
                      previousQuestion === questionItem.question
                        ? null
                        : questionItem.question,
                    )
                  }
                  className="flex min-h-12 w-full cursor-pointer items-center justify-between gap-6 px-5 py-4 text-left text-[#1D0A00] transition-colors hover:bg-[#F8F9F9] hover:text-[#BD0265] md:px-6"
                >
                  <span className="text-[18px] font-semibold leading-[130%] md:text-[20px]">
                    {questionItem.question}
                  </span>
                  <span
                    aria-hidden="true"
                    className={`shrink-0 transition-transform duration-300 ${
                      isExpanded ? "rotate-180" : "rotate-0"
                    }`}
                  >
                    <ChevronDownIcon className="h-5 w-5 md:h-6 md:w-6" />
                  </span>
                </button>
                <div
                  id={`faq-answer-${index}`}
                  className="grid overflow-hidden transition-[grid-template-rows,opacity] duration-300"
                  style={{
                    gridTemplateRows: isExpanded ? "1fr" : "0fr",
                    opacity: isExpanded ? 1 : 0,
                  }}
                >
                  <p className="overflow-hidden px-5 pb-5 text-[16px] font-normal leading-relaxed text-[#1D0A00]/85 md:px-6">
                    {questionItem.answer}
                  </p>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </SectionContainer>
  );
}
